--
-- Data for Name: about_us; Type: TABLE DATA; Schema: public; Owner: -
--

INSERT INTO public.about_us VALUES (1, '/uploads/media_655f2351de783.jpg', 'https://www.youtube.com/watch?v=Dmg9Y0KVnRo', '<div><font color="#7c7474"><span style="font-size: 16px;">En <b>Maosa</b>, nos hemos dedicado durante años a brindar soluciones confiables y de</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;">calidad a nuestros clientes. Con <b>Maosa Prime</b>, hemos llevado ese compromiso un</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;">paso más allá, creando una plataforma exclusiva que conecta a nuestros clientes</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;">con proveedores seleccionados cuidadosamente, para ofrecerles opciones que se</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;">ajusten a sus necesidades y les ayuden a optimizar sus operaciones.</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;"><br></span></font></div><div><font color="#7c7474"><span style="font-size: 16px;">Nuestro objetivo es simplificar el acceso a soluciones eficientes, basadas en</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;">confianza y profesionalismo. En <b>Maosa Prime</b>, cada decisión está pensada para</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;">que nuestros clientes tengan lo mejor a su alcance, con el respaldo de nuestra</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;">experiencia y dedicación.</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;"><br></span></font></div><div><font color="#7c7474"><span style="font-size: 16px;"><b>Maosa Prime</b>, más que una plataforma, es un espacio pensado para quienes</span></font></div><div><font color="#7c7474"><span style="font-size: 16px;">buscan lo mejor para su negocio.</span></font></div>', 'https://www.youtube.com/watch?v=yUXJjIvhZz8&t=9s', '2023-11-23 04:02:57', '2025-08-06 00:40:27');


