INSERT INTO public.heroes VALUES (2, 'public', '/uploads/media_6879269a7bc85.jpg', '¡Bienvenido a Maosa Prime!', '<p style="margin-bottom: 15px; color: black; text-align: center">En Maosa pensamos en ti, por eso hemos creado Maosa Prime, una plataformarn exclusiva para nuestros clientes, que te conecta con proveedores confiables para optimizar tu operatividad. Sabemos que tu tiempo es valioso, por eso hemos simplificado todo para ti.</p> <p style="margin-bottom: 15px; color: black; text-align: center">¡ Únete a Maosa Prime !</p>', '2025-07-07 23:33:44', '2026-03-10 22:36:09', 1);


