INSERT INTO public.listings VALUES (109, 1, 3, 8, '/uploads/media_686c6117d2b22.jpg', '/uploads/media_686c6117d2e99.jpg', 'SMART STATION', 'smart-station', '<p><span style="font-family: verdana, geneva, sans-serif;">EMPRESA MEXICANA DEDICADA A LA ADMINISTRACION DE GASOLINERAS CON UN SOFTWARE DE CONTROL VOLUM&Eacute;TRICO Y ADMINISTRATIVO PARA LLEVAR LA OPERACION, ADMINISTRACION Y CONTABILIDAD DE MANERA EFICIENTE Y CORRECTA PARA EL CUMPLIMIENTO NORMATIVO&nbsp;</span></p>', '7821049443', 'ADMINISTRACION@SMARTSTATION.COM', 'Calle Pinos, Geovillas del Real, 93164 Coatzintla, Veracruz de Ignacio de la Llave', 'https://site.smartstation.mx/', 1, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m17!1m12!1m3!1d3737.6130811663757!2d-97.44562092475823!3d20.481078981034614!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m2!1m1!2zMjDCsDI4JzUxLjkiTiA5N8KwMjYnMzUuMCJX!5e0!3m2!1ses-419!2smx!4v1751933900012!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'CONTROL VOLUMÉTRICO. SOPORTE TECNICO, CUMPLIMIENTO NORMATIVO', NULL, 1, 1, NULL, '2025-07-08 00:06:47', '2026-03-10 22:17:29');
INSERT INTO public.listings VALUES (121, 1, 5, 7, '/uploads/media_68eed8e78075a.jpeg', '/uploads/media_68eed8e7807b1.png', 'LUKI BARTER', 'luki-barter', '<p><span style="font-family: verdana, geneva, sans-serif;"><strong><span lang="ES-TRAD" style="font-size: 12pt;">EXPERTOS EN EL SECTOR ENERG&Iacute;A EN M&Eacute;XICO</span></strong></span></p>
<p><span style="font-family: verdana, geneva, sans-serif;"><strong><span lang="ES-TRAD" style="font-size: 12pt;">EMPRESA L&Iacute;DER EN SOLUCIONES Y SERVICIOS PROFESIONALES EN EL SECTORrnENERG&Eacute;TICO MEXICANO PARA LOGRAR PERMISOS, ACTUALIZACIONES, MODIFICACIONES, ANTErnCNE, ASEA Y SECRETARIA DE ENERG&Iacute;A.</span></strong></span></p>
<ul>
<li style="font-family: verdana, geneva, sans-serif;"><span lang="ES-TRAD" style="font-size: 12pt; font-family: verdana, geneva, sans-serif;">Hemos logrado la recuperaci&oacute;n de 46 permisos de la Caducidad ante la CNE,rn en un tiempo corto (tres meses en promedio).</span></li>
<li style="font-family: verdana, geneva, sans-serif;"><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif;">Hemos gestionado con &eacute;xito m&aacute;sde900permisosante la CNE.</span></li>
<li style="font-family: verdana, geneva, sans-serif;"><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif;">De Junio 2024 a la fecha, hemos logrado la obtenci&oacute;n de m&aacute;s de 20 permisos dern Comercializaci&oacute;n de Petrol&iacute;feros, es decir, el 95% de los permisos otorgados porrn la CNE en ese periodo.</span></li>
<li style="font-family: verdana, geneva, sans-serif;"><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif;">Nuestro equipo se conforma de exfuncionarios de la CNE, ASEA y secretaria dern Energ&iacute;a, aportando su experiencia en el ramo.</span></li>
<li style="font-family: verdana, geneva, sans-serif;"><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif;">Con los cambios actuales en leyes secundarias en el sector energ&eacute;tico, se harn realizado un an&aacute;lisis minucioso de las afectaciones y oportunidades que tienenrn nuestros clientes, por lo que podemos aportar de manera considerable a lograr susrn metas.</span></li>
</ul>', '5543035371', 'JULIO@LUKIBARTER.COM', 'Londres 61 Piso 14, torre A, Oficina E12, Col Juárez, Alcaldía Cuauhtémoc, 06600 Ciudad de México, CDMX', NULL, 1, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3762.6575662410914!2d-99.16339122307231!3d19.42719608185116!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x85d1ff33e9e9aac5%3A0xb9f9b77345981fa!2sLondres%2061-Piso%2014%2C%20torre%20A%2C%20Oficina%20E12%2C%20Ju%C3%A1rez%2C%20Cuauht%C3%A9moc%2C%2006600%20Ciudad%20de%20M%C3%A9xico%2C%20CDMX!5e0!3m2!1ses-419!2smx!4v1760483527710!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'EMPRESA LÍDER EN SOLUCIONES Y SERVICIOS PROFESIONALES EN EL SECTOR ENERGÉTICO', 'SOMOS LA EMPRESA LÍDER EN SOLUCIONES Y SERVICIOS PROFESIONALES EN EL SECTOR ENERGÉTICO MEXICANO PARA LOGRAR PERMISOS, ACTUALIZACIONES, MODIFICACIONES, ANTE CNE, ASEA Y SECRETARIA DE ENERGÍA.', 1, 1, NULL, '2025-10-14 23:12:39', '2026-03-10 22:06:24');
INSERT INTO public.listings VALUES (107, 1, 2, 6, '/uploads/media_687927b3a9abd.jpg', '/uploads/media_687927b3a9f6a.jpg', 'MG MATERIAL GRAFICO', 'mg-material-grafico', '<p><span style="color: #080809; font-family: verdana, geneva, sans-serif;"><strong>Publicidad Impresa y Articulos promocionales para tu Empresa, Escuela o Eventos sociales, Distribuidores.&nbsp;</strong></span></p>
