INSERT INTO public.listings VALUES (108, 1, 3, 6, '/uploads/media_6841d1e038301.png', '/uploads/media_6841d1e038589.png', 'Kernotek S.A. de C.V.', 'kernotek-sa-de-cv', '<p><span style="color: #080809; font-family: verdana, geneva, sans-serif;">Con nuestra soluci&oacute;n de control volum&eacute;trico desarrollado para gasolineras podr&aacute;s gestionar la operaci&oacute;n comercial y administrativa de tu estaci&oacute;n de servicio desde cualquier dispositivo y lugar. Accede a todos los reportes en tiempo real.</span></p>
<p><span style="font-family: verdana, geneva, sans-serif;"><strong style="color: #222222; font-size: small;">Empresa con m&aacute;s de 20 a&ntilde;os de experiencia en tecnolog&iacute;a e innovaci&oacute;n para el sector de hidrocarburos</strong><span style="color: #222222; font-size: small;">, especializada en soluciones para autoconsumos, estaciones de servicio, distribuidoras y comercializadoras. Ofrece una gama integral de servicios y productos como:</span></span></p>
<ul style="color: #222222; font-family: Arial, Helvetica, sans-serif; font-size: small; margin-top: 0cm;">
<li style="margin-left: 0cm; font-family: verdana, geneva, sans-serif;"><span style="font-family: verdana, geneva, sans-serif;">Control volum&eacute;trico</span></li>
<li style="margin-left: 0cm; font-family: verdana, geneva, sans-serif;"><span style="font-family: verdana, geneva, sans-serif;">Puntos de venta y terminales m&oacute;viles</span></li>
<li style="margin-left: 0cm; font-family: verdana, geneva, sans-serif;"><span style="font-family: verdana, geneva, sans-serif;">Soluciones en la nube y software administrativo</span></li>
<li style="margin-left: 0cm; font-family: verdana, geneva, sans-serif;"><span style="font-family: verdana, geneva, sans-serif;">Equipos de comunicaci&oacute;n y consolas a dispensarios</span></li>
<li style="margin-left: 0cm; font-family: verdana, geneva, sans-serif;"><span style="font-family: verdana, geneva, sans-serif;">Servidores dedicados y seguridad cibern&eacute;tica</span></li>
<li style="margin-left: 0cm; font-family: verdana, geneva, sans-serif;"><span style="font-family: verdana, geneva, sans-serif;">Impresoras, pedestales y antenas Wi-Fi</span></li>
<li style="margin-left: 0cm; font-family: verdana, geneva, sans-serif;"><span style="font-family: verdana, geneva, sans-serif;">Enfocada en mejorar la eficiencia operativa y la seguridad de sus clientes.</span></li>
</ul>', '464 654 1157', 'ventas@kernotek.mx', 'Convenciones Cantabria, Morelia, Mich', 'https://www.kernotek.mx/', 1, 0, 0, NULL, NULL, NULL, 1, 1, NULL, '2025-06-05 23:20:32', '2026-03-10 22:17:08');
INSERT INTO public.listings VALUES (114, 1, 1, 11, '/uploads/media_688d57eec6657.jpg', '/uploads/media_688d57eec689f.jpg', 'E-MECSA', 'e-mecsa', '<p><span id="docs-internal-guid-50a3b7f5-7fff-8d43-aef6-6f1e4d247d44"><span style="font-size: 12pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; white-space-collapse: preserve;">Consultoría energética <b>especializada</b> en cumplimiento <b>normativo</b>, <b>regulaciones</b> ambientales, permisos <b>CRE/CNE y ASEA, SASISOPA</b>, <b>análisis de riesgos, impacto ambiental y desarrollo de proyectos sostenibles</b> en el sector hidrocarburos y gas LP. Servicios técnicos, jurídicos y regulatorios para estaciones de servicio, comercializadores e industrias energéticas</span></span></p>', '22-15-86-3496', 'contacto@e-mecsa.com', 'Calle Alejandra NO. 512-S11, Col. Santiago Momoxpan,  San Pedro Cholula, Puebla, C.P. 72760', 'https://www.e-mecsa.com/', 0, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3770.772323154791!2d-98.27567983967283!3d19.073745359243357!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x85cfc7cb6b8fd219%3A0x6ab29ec2e1e63f84!2sE-MECSA!5e0!3m2!1ses!2smx!4v1753714877128!5m2!1ses!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'Consultoría energética especializada en cumplimiento normativo', 'Consultoría energética especializada en cumplimiento normativo, regulaciones ambientales, permisos CRE/CNE y ASEA, SASISOPA, análisis de riesgos, impacto ambiental y desarrollo de proyectos sostenibles en el sector hidrocarburos', 1, 1, NULL, '2025-08-02 00:12:30', '2025-08-02 00:21:15');
