INSERT INTO public.listings VALUES (112, 1, 3, 9, '/uploads/media_687ec3f1d78ba.png', '/uploads/media_687ec3f1d7cfc.jpg', 'Nexus Fuel', 'nexus-fuel', '<div><span style="font-family: verdana, geneva, sans-serif;"><span style="font-size: 16px; white-space-collapse: preserve;">Nexus Fuel es un software especializado para el sector gasolinero, dise&ntilde;ado para cubrir toda la cadena de valor: autoconsumo, estaciones de servicio, fletes, distribuidoras y comercializadoras. Contamos con nuestra propia casa de desarrollo, lo que nos permite innovar constantemente y adaptarnos a las necesidades del mercado, especialmente a las del gasolinero mexicano. Todo esto garantizando siempre el cumplimiento regulatorio y ayudando a nuestros clientes a crecer, optimizar y diferenciarse.</span></span></div>
<div><span style="font-family: verdana, geneva, sans-serif;"><span style="font-size: 16px; white-space-collapse: preserve;">&nbsp;</span></span></div>
<div><span style="font-family: verdana, geneva, sans-serif;"><span style="font-size: 16px; white-space-collapse: preserve;">Software especializado en el sector gasolinero, con soluciones para cada etapa de la cadena de suministro, un enfoque innovador y pleno cumplimiento de la normatividad nacional.</span></span></div>', '664 681 3494', 'info@nexusfuel.com', 'Río Suchiate #13, Tijuana, Baja California, 22015', 'https://www.nexusfuel.com/', 0, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3364.138883204436!2d-117.02151242387066!3d32.522437473771085!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x80d9390226587bd3%3A0xd2420197bb0c3f5f!2sGXCJ%2BXC%2C%20Tijuana%2C%20Baja%20California!5e0!3m2!1ses-419!2smx!4v1753138358424!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'Software especializado en sector de combustibles', 'Software especializado en sector de combustibles, control volumétrico, plan de lealtad gasolineras, ERP Contabilidad gasolineras', 1, 1, NULL, '2025-07-21 22:49:21', '2026-03-10 22:20:26');
INSERT INTO public.listings VALUES (113, 1, 3, 10, '/uploads/media_687ec9bf116bb.png', '/uploads/media_687ec9bf11d06.png', 'CABS - Centro de Abastecimiento de Bienes y Servicios', 'cabs-centro-de-abastecimiento-de-bienes-y-servicios', '<p><span style="font-family: verdana, geneva, sans-serif;">Somos un <strong>Centro de Abastecimiento de Bienes y Servicios en el sector gasolinero</strong>. Con sede en Le&oacute;n, Guanajuato y con m&aacute;s de <strong>15 a&ntilde;os de experiencia</strong>. Nuestro equipo de trabajo est&aacute; capacitado para resolver sus dudas, <strong>brindando calidad en nuestro servicio</strong> para el empresario gasolinero y adecu&aacute;ndonos a sus <strong>necesidades</strong>.</span></p>
<p><span style="font-family: verdana, geneva, sans-serif;">Tel&eacute;fono adicional: 477 764 6475</span></p>', '477 764 6816', 'cabsleon100@gmail.com', 'Blvd. Vasco de Quiroga #2728 León 1, C.P. 37179, León Gto.', 'https://www.cabsleon.com/', 0, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d7442.632331504797!2d-101.65038742421254!3d21.13981248053747!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x842bbeffd6e6e721%3A0x389334e7fcd7d6a5!2zNDlRMitXViwgTGXDs24sIEd1YW5hanVhdG8!5e0!3m2!1ses-419!2smx!4v1753139782198!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', NULL, 'Uniformes para gasolineras PEMEX, BP y G500, opciones personalizadas. Botas industriales antiderrapantes 100% piel, resistentes a gasolina y diésel.', 1, 1, NULL, '2025-07-21 23:14:07', '2026-03-10 22:20:46');
INSERT INTO public.listings VALUES (116, 1, 3, 8, '/uploads/media_68a0bb0eab63c.jpg', '/uploads/media_68a0bb0eaba1a.jpg', 'FUELCO DE MEXICO S.A. DE C.V.', 'fuelco-de-mexico-sa-de-cv', '<p>La calibración de tanques de almacenamiento la realizamos por diferentes métodos que tenemos acreditados, entre ellos son:</p><ul><li>Método de mediciones internas (tanques subterráneos)</li><li>Método húmedo (tanques subterráneos y superficiales)</li><li>Método óptico (para tanques verticales)</li><li>Método de mediciones externas (tanques superficiales de pared sencilla)</li></ul><p><br></p><p>La calibración de los instrumentos lo hacemos por el método de lectura directa con instrumentos patrón.</p><p>Integración de valores obtenidos en calibraciones a la consola de medición.</p><p>Pruebas de hermeticidad a tanques de almacenamiento y tuberías.</p><p>Medición de espesores por ultrasonido, para conocer la integridad mecánica de los tanques. Este servicio sirve para el alargamiento de la útil si ya el tanque tiene entre 20 y 30 años, dependerá de la vida útil que les dio el proveedor.</p><p>Limpieza de tanques de almacenamiento, nos introducimos dentro y retiramos los lodos.</p>', '921 196 6543', 'directivoventas@fuelco.com.mx', 'Av. José María, Av Pino Suárez 500, Manuel Avila Camacho, 96420 Coatzacoalcos', 'https://fuelco.com.mx', 0, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d30331.975056626114!2d-94.47775034754152!3d18.141010554327757!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x85e9825610950001%3A0x704e60a40c8a85f7!2sFUELCO%20DE%20M%C3%89XICO!5e0!3m2!1ses-419!2smx!4v1755365620062!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'Servicios metrológicos y pruebas no destructivas; ejerciendo siempre con responsabilidad y ética profesional.', 'Servicios metrológicos y pruebas no destructivas; ejerciendo siempre con responsabilidad y ética profesional. Contamos con la tecnología y experiencia para ofrecer servicios y resultados a satisfacción', 1, 1, NULL, '2025-08-16 17:08:30', '2025-08-16 17:33:57');
INSERT INTO public.listings VALUES (117, 1, 3, 6, '/uploads/media_68a0c01aa9d43.jpg', '/uploads/media_68a0c01aaa248.jpg', 'GASLIGHT SYSTEM', 'gaslight-system', '<p><b>Nuestro control volumétrico una herramienta esencial para gestionar y optimizar el flujo, almacenamiento y distribución de hidrocarburos en diferentes eslabones de la cadena de suministro.</b></p><p><b>Estaciones de Servicio (Gasolineras):</b></p><ul><li>Monitoreo de inventarios en tanques subterráneos.</li><li>Detección de pérdidas (evaporación, fugas o robos).</li><li>Conciliación entre recepciones y entregas.</li></ul><p><b>Distribuidoras y Comercializadoras:</b></p><ul><li>Control de entregas y recepciones.</li></ul><p><b>Transporte (Camiones Cisterna):</b></p><ul><li>Validación de recepciones y entregas.</li></ul><p><b>Autoconsumo (Flotas, Industrias, Mineras):</b></p><ul><li>Control de consumo de maquinaria y vehículos propios.</li><li>Prevención de desvíos no autorizados.</li><li>Cumpliendo con el 100% de normativas volumétricas y fiscales.</li></ul>', '4521252899', 'garcia_salvador30@hotmail.com', 'AV CHIAPAS 93 COL RAMON FARIAS EN URUAPAN MICHOACAN', 'https://gaslight-michoacan.com', 0, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3762.7306323407224!2d-102.05070622425221!3d19.424041181853557!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x842de24032514abd%3A0xc02de06bd95eecd7!2sC.%20Chiapas%2093%2C%20Ram%C3%B3n%20Farias%2C%2060050%20Uruapan%2C%20Mich.!5e0!3m2!1ses-419!2smx!4v1755365544533!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'CONTROL VOLUMETRICO, PARA EL SECTOR HIDRO CARBUROS', 'CONTROL VOLUMETRICO, PARA EL SECTOR HIDRO CARBUROS', 1, 1, NULL, '2025-08-16 17:30:02', '2025-08-16 17:32:45');
INSERT INTO public.listings VALUES (118, 1, 6, 7, '/uploads/media_68b9da038bc7d.jpeg', '/uploads/media_68b9da038bcd1.jpeg', 'Payclip S. de R.L. de C.V', 'payclip-s-de-rl-de-cv', '<p>Con Clip, cobrar con tarjeta es simple, seguro y rápido. Elige la terminal ideal para tu negocio y empieza a recibir pagos en minutos. ¡Sin contratos ni complicaciones!</p><p><a href="https://www.clip.mx/?srsltid=AfmBOop4WtV9ARN9cY4c5XdIca0b7DrUI9EpNsHXSot23MjSs4MBoYsO" target="_blank">Enlace | Clip</a><br></p>', '55 6393 2300', 'help@clip.mx', 'AVENIDA INSURGENTES SUR 1457 INT. PISO 23 COL. INSURGENTES MIXCOAC, BENITO JUÁREZ, CIUDAD DE MÉXICO, C.P. 03920', 'https://www.clip.mx/?srsltid=AfmBOop4WtV9ARN9cY4c5XdIca0b7DrUI9EpNsHXSot23MjSs4MBoYsO', 0, 0, 0, NULL, NULL, NULL, 1, 1, NULL, '2025-09-04 18:27:15', '2025-09-04 18:29:45');
INSERT INTO public.listings VALUES (119, 1, 3, 13, '/uploads/media_68b9de258d467.jpg', '/uploads/media_68b9de258d4c8.png', 'PROMOECO', 'promoeco', '<p>Empresa líder en ofrecer servicios integrales para estaciones de servicio, podrá encontrar los mejores accesorios que harán que su estación de servicio funcione a la perfección.</p>', '81 81255800', 'info@promoeco.com.mx', 'Nardo 2232 col. Moderna, N.L', 'https://promoeco.mx/', 1, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d6010.559760754836!2d-100.2905524!3d25.7010743!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x8662951326edc279%3A0x179983a0ac610b76!2sPromoeco!5e1!3m2!1ses-419!2smx!4v1757011665504!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'Servicio, insumo, gasolinera, estación, equipamiento, capacitación', 'Servicio, insumo, gasolinera, estación, equipamiento, capacitación', 1, 1, NULL, '2025-09-04 18:44:53', '2025-09-04 18:48:07');
INSERT INTO public.listings VALUES (120, 1, 7, 10, '/uploads/media_68d5a06595170.jpg', '/uploads/media_68d5a065951db.jpg', 'Brisco Uniformes', 'brisco-uniformes', '<p><span style="font-family: "Fira Sans", sans-serif; font-size: 14.4px; background-color: rgb(232, 238, 241);">Somos una empresa con más de 20 años de experiencia en la </span><strong style="box-sizing: inherit; font-family: "Fira Sans", sans-serif; font-size: 14.4px; background-color: rgb(232, 238, 241);">manufactura y comercialización de uniformes industriales y calzado de seguridad</strong><span style="font-family: "Fira Sans", sans-serif; font-size: 14.4px; background-color: rgb(232, 238, 241);">. Contamos con infraestructura moderna y tecnología de punta para el diseño, confección y bordado de nuestros productos.</span></p>', '4621028084', 'ventas@briscoindustrial.com', 'Cebú #2839, Ganadera, CP. 36555. Irapuato, Gto.', 'https://www.uniformesbrisco.com/', 1, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m14!1m8!1m3!1d6241.571019785806!2d-101.3705149!3d20.6583423!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x842c7e2eff4a3f7b%3A0xf21470a32628d307!2sBrisco%20Uniformes%20para%20Gasolineras!5e1!3m2!1ses-419!2smx!4v1758830666018!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'Empresa con experiencia en la manufactura y comercialización de uniformes industriales y calzado de seguridad', 'Somos una empresa con más de 20 años de experiencia en la manufactura y comercialización de uniformes industriales y calzado de seguridad', 1, 1, NULL, '2025-09-25 20:04:53', '2025-09-25 20:09:10');
INSERT INTO public.listings VALUES (122, 1, 3, 14, '/uploads/media_690910e8899a1.png', '/uploads/media_690910e8899f0.jpg', 'eServices', 'eservices', '<p>En <b>eServices </b>somos una empresa consolidada rnen el sector de hidrocarburos, <b>con más de 25 rnaños de experiencia</b> en gestión regulatoria y rnacompañamiento especializado a rnpermisionarios de petrolíferos en todo México.</p><p>Nuestro objetivo es brindar soporte integral y rncertidumbre jurídica, facilitando el rncumplimiento de obligaciones legales, técnicas rny administrativas ante instancias como <b>ASEA, rnCNE, SENER, PROFECO</b>, entre otras. Diseñamos rnestrategias a la medida que garantizan rnoperaciones seguras, transparentes y dentro del rnmarco normativo vigente.</p>', '+526645947582', 'comercial@eservicesmx.com', 'Calle del Pedregal No. 38, Col. El Pedregal, C.P. 22104, Tijuana, Baja California', 'https://eservicesmx.com/', 1, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m14!1m8!1m3!1d420.59093184331897!2d-116.9655211!3d32.5067129!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x80d939538ea66ffb%3A0xf28010ec34f80d0!2sESERVICES!5e0!3m2!1ses-419!2smx!4v1762202190488!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'empresa consolidada en el sector de hidrocarburos en  gestión regulatoria y acompañamiento especializado a permisionarios de petrolíferos', 'En eServices somos una empresa consolidada en el sector de hidrocarburos, con más de 25 años de experiencia en gestión regulatoria y acompañamiento especializado a permisionarios de petrolíferos en todo México.', 1, 1, NULL, '2025-11-03 20:30:32', '2025-11-03 20:39:57');
INSERT INTO public.listings VALUES (124, 1, 5, 6, '/uploads/media_690d28c374a7f.png', '/uploads/media_690d28c374ad5.png', 'ARQ. BENHUR VILLAGRAN GARCIA', 'arq-benhur-villagran-garcia', '<p><span style="color: #080809; font-family: verdana, geneva, sans-serif;">DISE&Ntilde;O DE PROYECTOS ARQUITECT&Oacute;NICOS, VENTA DE BIENES RA&Iacute;CES, RENDERIZACION DE PROYECTOS, PLANOS, INTERIORISMO, REMODELACION Y MAS</span></p>', '4432021102', 'ARQ_BVG@YAHOO.COM.MX', 'BENEDICTINOS #129 FRACC EL MONASTERIO CP 58090 MORELIA', NULL, 1, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d50231.981457688606!2d-101.21098092941826!3d19.727002273414595!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x842d0e70458f7e77%3A0x71b5c6c09438746b!2sAv%20Francisco%20I.%20Madero%20Pte%2C%20Centro%20hist%C3%B3rico%20de%20Morelia%2C%2058000%20Morelia%2C%20Mich.!5e1!3m2!1ses-419!2smx!4v1762470063732!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'DISEÑO DE PROYECTOS ARQUITECTÓNICOS, VENTA DE BIENES RAÍCES', 'DISEÑO DE PROYECTOS ARQUITECTÓNICOS, VENTA DE BIENES RAÍCES, RENDERIZACION DE PROYECTOS, PLANOS, INTERIORISMO, REMODELACION', 1, 1, NULL, '2025-11-06 23:01:23', '2026-03-10 22:14:38');
INSERT INTO public.listings VALUES (126, 1, 5, 6, '/uploads/media_6924967e3b492.jpeg', '/uploads/media_6924967e3b50a.jpeg', 'GATRADIS CORPORATION', 'gatradis-corporation', '<p><span style="font-family: verdana, geneva, sans-serif;"><strong>GATRADIS </strong>es una empresa mexicana con m&aacute;s de 10 a&ntilde;os de experiencia en la rnindustria energ&eacute;tica, especializada en ofrecer soluciones integrales para el rnalmacenamiento, transporte y medici&oacute;n de hidrocarburos. Con un laboratorio de rncalibraci&oacute;n acreditado y una flota de transporte propia, brindan servicios de alta rningenier&iacute;a, inspecci&oacute;n, construcci&oacute;n y mantenimiento para terminales de rncombustible, tanques, skids, as&iacute; como estaciones de servicio y de autoconsumo</span></p>', '4461333115', 'comercial@gatradis.com', 'URUGUAY 194, LAS AMERICAS 58270, MORELIA, MICHOACAN 3', 'https://gatradis.com', 0, 0, 0, NULL, 'Empresa mexicana líder en ingeniería energética, transporte de combustible, calibración de tanques y diseño de terminales de hidrocarburos.', 'GATRADIS ofrece servicios de alta precisión en medición volumétrica, inspección, construcción de tanques y skids, así como mantenimiento y transporte seguro de combustibles en toda la República Mexicana.', 1, 1, NULL, '2025-11-24 17:31:42', '2026-03-10 22:15:26');
INSERT INTO public.listings VALUES (123, 1, 7, 8, '/uploads/media_690d2673a8b9f.jpeg', '/uploads/media_690d2673a8c08.png', 'COMEBRIXA CAROLINA BRITO', 'comebrixa-carolina-brito', '<p><span style="font-family: verdana, geneva, sans-serif;"><span style="font-size: 12.0pt;">Empresa dedicada a la comercializaci&oacute;n dernproductos y servicios para el Sector Gasolinero, iluminaci&oacute;n Led y Microled,rninstalaci&oacute;n de luminarias, instalaci&oacute;n el&eacute;ctrica, Estudios lum&iacute;nicos, etc.</span></span></p>', '2281794243', 'comebrixa@yahoo.com', 'Enrique C Rébsamen #2, Zona Centro, Mártires de Chicago, 91094 Xalapa-Enríquez', 'http://www.comebrixa.com/', 1, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3760.440629949782!2d-96.9191374230709!3d19.52268748177601!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x85db321ca1f225d9%3A0xb706e9efe195a786!2sG3FM%2B39%2C%20Xalapa-Enr%C3%ADquez%2C%20Veracruz!5e0!3m2!1ses-419!2smx!4v1762469635878!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'PROVEEDOR DE TODO TIPO DE LUMINARIAS PARA LA INDUSTRIA GASOLINERA', 'PROVEEDOR DE TODO TIPO DE LUMINARIAS PARA LA INDUSTRIA GASOLINERA', 1, 1, NULL, '2025-11-06 22:51:31', '2026-03-10 22:14:14');
INSERT INTO public.listings VALUES (125, 1, 5, 15, '/uploads/media_69248ee63499e.png', '/uploads/media_69248ee634aba.png', 'KIOSKO®', 'kiosko', '<p><span style="text-indent: -24px; font-family: verdana, geneva, sans-serif;">Somos una cadena de tiendas de formato peque&ntilde;o 100% mexicana, con m&aacute;s de 22 a&ntilde;os de experiencia y m&aacute;s de 890 establecimientos ubicados a lo largo del pac&iacute;fico de M&eacute;xico. </span></p>
<p><span style="text-indent: -24px; font-family: verdana, geneva, sans-serif;">A&ntilde;o con a&ntilde;o nos hemos convertido en parte del estilo de vida de muchas personas, ya que en KIOSKO celebramos las tradiciones de los barrios mexicanos y la alegr&iacute;a de su gente, brindando la mejor y m&aacute;s cercana experiencia de compra a todos nuestros clientes.</span></p>', '312 313 4400', 'jsalas@gocsa.com.mx', 'Av. Tecomán Sur No. 99-F, Col. El Moralete, CP 28010, Colima, Colima, México. (Oficinas corporativas)', 'https://mikiosko.mx/', 0, 0, 0, '<iframe src="https://www.google.com/maps/embed?pb=!1m14!1m8!1m3!1d25193.435750402474!2d-103.7198723!3d19.2282504!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x8425500c272e419f%3A0xb0243555280fea9a!2sAv%20Tecom%C3%A1n%2099-f%2C%20Infraestructura%20Urbana%2C%2028060%20Colima%2C%20Col.!5e1!3m2!1ses-419!2smx!4v1764003639871!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', 'Tienda de conveniencia, KIOSKO, México, abarrotes, snacks, bebidas, Jalisco, Colima, Nayarit, Sinaloa, pago de servicios, experiencia', 'Tienda de conveniencia, KIOSKO, México, abarrotes, snacks, bebidas, Jalisco, Colima, Nayarit, Sinaloa, pago de servicios, experiencia', 0, 1, NULL, '2025-11-24 16:59:18', '2026-03-10 22:15:05');
INSERT INTO public.listings VALUES (127, 1, 8, 6, '/uploads/media_6939acd027e1c.jpeg', '/uploads/media_6939acd027e7d.jpeg', 'Bull Up', 'bull-up', '<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif;">En Bull Up entendemos profundamente el entorno industrial y corporativo.&nbsp;</span></p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif;">Contamos con experiencia en normativas, preparaci&oacute;n para auditor&iacute;as y medici&oacute;n de datos clave que permiten a las empresas optimizar sus procesos, mejorar su trazabilidad y adoptar herramientas digitales que impulsan su productividad.&nbsp; </span></p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif;">Nuestro enfoque combina&nbsp;<strong>estrategia, dise&ntilde;o, comunicaci&oacute;n y sistemas</strong>&nbsp;para ofrecer soluciones integrales que realmente transforman.</span></p>', '+524431179599', 'hola@bullup.com.mx', 'Morelia, Mich', 'https://www.bullup.com.mx/', 0, 1, 0, NULL, 'Marketing, Web, Diseño, publicidad, redes sociales, comunicación, branding.', 'Marketing, Web, Diseño, publicidad, redes sociales, comunicación, branding.', 1, 1, NULL, '2025-12-10 17:24:32', '2026-03-10 22:15:49');
INSERT INTO public.listings VALUES (106, 1, 1, 7, '/uploads/media_683c9ea3f3515.png', '/uploads/media_683c9ea402537.png', 'SUSTENTABILIDAD EMPRESARIAL Y VALOR AGREGADO, S.C', 'sustentabilidad-empresarial-y-valor-agregado-sc', '<p><span style="color: #000000; font-family: verdana, geneva, sans-serif;">Somos una empresa de<strong> consultor&iacute;a estrat&eacute;gica</strong>, con m&aacute;s de 10 a&ntilde;os de presencia en <strong>M&eacute;xico</strong> y <strong>Latinoam&eacute;rica</strong>, favoreciendo el desarrollo de empresas m&aacute;s sustentables. Dise&ntilde;amos, desarrollamos e implementamos servicios y soluciones para un crecimiento econ&oacute;mico m&aacute;s sustentable y una adecuada <strong>administraci&oacute;n de los riesgos</strong>. </span></p>
<p><span style="color: #000000; font-family: verdana, geneva, sans-serif;">Quienes laboramos en <strong>Sustentabilidad Empresaria</strong>l somos expertos en distintas &aacute;reas empresariales. Contamos con las competencias necesarias para detonar: <strong>valor econ&oacute;mico, ambiental y social, considerando las necesidades actuales, futuras, as&iacute; como el contexto interno y externo.</strong></span></p>', '5579179840', 'contacto@sustentabilidad.com.mx', 'Avenida Lago Alberto 375, CDMX, CDMX 11520, MX', 'https://sustentabilidad.com.mx/', 1, 1, 1, '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3762.3466699055625!2d-99.19246132515643!3d19.440614681840465!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x85d1f8a8209c1ac9%3A0x3580c90d80f9e13b!2sLago%20Alberto%20375%2C%20Granada%2C%20Miguel%20Hidalgo%2C%2011320%20Ciudad%20de%20M%C3%A9xico%2C%20CDMX!5e0!3m2!1ses-419!2smx!4v1748712544311!5m2!1ses-419!2smx" width="100%" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>', NULL, NULL, 1, 1, NULL, '2025-06-01 18:40:36', '2026-03-10 22:16:19');
INSERT INTO public.listings VALUES (111, 1, 3, 6, '/uploads/media_68792a877ea0e.png', '/uploads/media_68792a877ec50.jpg', 'CADISA - Controles Administrativos Integrales SA de CV', 'cadisa-controles-administrativos-integrales-sa-de-cv', '<div>
<div><span style="font-family: verdana, geneva, sans-serif;">Nos ubicamos en 19 estados de la Rep&uacute;blica Mexicana, actualmente, nuestro&nbsp; sistema tiene presencia en los estados de Baja California Norte, Baja California Sur,&nbsp; Sonora, Sinaloa, Chihuahua, Coahuila, Quer&eacute;taro, Puebla, Nuevo Le&oacute;n, Jalisco,Nayarit, Hidalgo, Colima, Ciudad de M&eacute;xico, Estado de M&eacute;xico, Tamaulipas,&nbsp; Aguascalientes, Morelos y Guerrero.&nbsp;</span></div>
<div>&nbsp;</div>
<div><span style="font-family: verdana, geneva, sans-serif;">Nuestro Sistema de Control Volum&eacute;trico &ldquo;CV RADEC&rdquo; contempla a todos los&nbsp; involucrados en la cadena de hidrocarburos, sin embargo, se personaliza seg&uacute;n la&nbsp; operaci&oacute;n de cada permisionario.&nbsp;</span></div>
<div><span style="font-family: verdana, geneva, sans-serif;">&ldquo;CV RADEC&rdquo; es un sistema de control volum&eacute;trico eficaz y eficiente, con las&nbsp; mejores opciones de cumplimiento para:</span></div>
</div>
<div>
<ul>
<li style="font-family: verdana, geneva, sans-serif;"><span style="font-family: verdana, geneva, sans-serif;">Transporte de combustible (contemplando carta porte y medidores&nbsp; din&aacute;micos).&nbsp;</span></li>
<li style="font-family: verdana, geneva, sans-serif;"><span style="font-family: verdana, geneva, sans-serif;">Autoconsumos, minas y consumidores obligados.&nbsp;</span></li>
