INSERT INTO public.privacy_policies VALUES (1, '<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;"><strong>Maosa Prime</strong> es un servicio ofrecido por <strong>Manuel Arroyo Ortega y Sucesores, S.A. de C.V. (Maosa)</strong>, con domicilio en Frente Estaci&oacute;n FF CC colonia anahuac Zacapu Michoac&aacute;n Cp 58630, quien ser&aacute; el responsable del tratamiento de sus datos personales.</span></p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;"><strong>Finalidad del tratamiento de los datos personales:</strong></span></p>
<p><span style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;">Los datos personales que usted nos proporciona ser&aacute;n utilizados para las&nbsp;siguientes finalidades:</span></p>
<ul>
<li style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;"><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;">Registrar su acceso a la plataforma Maosa Prime.</span></li>
<li style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;"><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;">Verificar su identidad como cliente activo de Maosa.</span></li>
<li style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;"><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;">Ofrecerle acceso a proveedores y servicios dentro de la plataforma.</span></li>
<li style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;"><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;">Contactarlo con fines de atenci&oacute;n, seguimiento y mejora del servicio.</span></li>
<li style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;"><span style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;">Enviar informaci&oacute;n relevante sobre productos, servicios o beneficios&nbsp;relacionados con Maosa Prime.</span></li>
<li style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;"><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;">Generar estad&iacute;sticas internas sobre el uso de la plataforma.</span></li>
</ul>
<p>&nbsp;</p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;"><strong>Datos personales recabados:</strong></span></p>
<p><span style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;">Los datos que podemos recabar incluyen: nombre completo, raz&oacute;n social, RFC, correo electr&oacute;nico, n&uacute;mero telef&oacute;nico, domicilio fiscal, y cualquier otro dato necesario para validar su relaci&oacute;n comercial con Maosa.</span></p>
<p>&nbsp;</p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;"><strong>Transferencia de datos personales:</strong></span></p>
<p><span style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;">Maosa no compartir&aacute; sus datos personales con terceros, salvo que sea necesario&nbsp;para cumplir con obligaciones legales o requerimientos de autoridad competente.</span></p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;">No se realizar&aacute;n transferencias de datos sin su consentimiento expreso.</span></p>
<p>&nbsp;</p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;"><strong>Medidas de seguridad:</strong></span></p>
<p><span style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;">Maosa ha implementado medidas administrativas, t&eacute;cnicas y f&iacute;sicas para proteger&nbsp;sus datos personales contra da&ntilde;o, p&eacute;rdida, alteraci&oacute;n, destrucci&oacute;n o el uso,&nbsp;acceso o tratamiento no autorizado.</span></p>
<p>&nbsp;</p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;"><strong>Derechos ARCO (Acceso, Rectificaci&oacute;n, Cancelaci&oacute;n y Oposici&oacute;n):</strong></span></p>
<p><span style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;">Usted tiene derecho a acceder a sus datos personales, rectificarlos si son&nbsp;inexactos o incompletos, cancelarlos u oponerse a su uso para fines espec&iacute;ficos.</span></p>
<p><span style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;">Para ejercer estos derechos, puede enviar su solicitud al correo: [insertar correo&nbsp;oficial].</span></p>
<p>&nbsp;</p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;"><strong>Cambios al aviso de privacidad:</strong></span></p>
<p><span style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;">Este aviso de privacidad puede ser modificado en cualquier momento. Las&nbsp;actualizaciones ser&aacute;n publicadas en la plataforma Maosa Prime o mediante los&nbsp;medios que Maosa considere adecuados.</span></p>
<p>&nbsp;</p>
<p><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;"><strong>Contacto:</strong></span></p>
<p><span style="font-family: verdana, geneva, sans-serif; font-size: 12pt; color: #000000;">Para cualquier duda sobre este aviso de privacidad, puede comunicarse con nosotros al correo:&nbsp;</span><span style="font-size: 12pt; font-family: verdana, geneva, sans-serif; color: #000000;">ventas@maosa.com.mx o al tel&eacute;fono: 443 141 5734.</span></p>', '2023-11-23 04:06:08', '2026-03-10 22:27:41');


